  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_FSM_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, unused_err_o, CLK_, RST_)
`define ASSERT_PRIM_COUNT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_DOUBLE_LFSR_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_REG_WE_ONEHOT_ERROR_TRIGGER_ERR(NAME_, REG_TOP_HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ERR(NAME_, \
    REG_TOP_HIER_.u_prim_reg_we_check.u_prim_onehot_check, ERR_, GATE_, MAX_CYCLES_, CLK_, RST_)
`endif 
`ifndef PRIM_FLOP_MACROS_SV
`define PRIM_FLOP_MACROS_SV
`define PRIM_FLOP_CLK clk_i
`define PRIM_FLOP_RST rst_ni
`define PRIM_FLOP_RESVAL '0
`define PRIM_FLOP_A(__d, __q, __resval = `PRIM_FLOP_RESVAL, __clk = `PRIM_FLOP_CLK, __rst_n = `PRIM_FLOP_RST) \
  always_ff @(posedge __clk or negedge __rst_n) begin \
    if (!__rst_n) begin                               \
      __q <= __resval;                                \
    end else begin                                    \
      __q <= __d;                                     \
    end                                               \
  end
`define PRIM_FLOP_SPARSE_FSM(__name, __d, __q, __type, __resval = `PRIM_FLOP_RESVAL, __clk = `PRIM_FLOP_CLK, __rst_n = `PRIM_FLOP_RST, __alert_trigger_sva_en = 1) \
  `ifdef SIMULATION                                   \
    prim_sparse_fsm_flop #(                           \
      .StateEnumT(__type),                            \
      .Width($bits(__type)),                          \
      .ResetValue($bits(__type)'(__resval)),          \
      .EnableAlertTriggerSVA(__alert_trigger_sva_en), \
      .CustomForceName(`PRIM_STRINGIFY(__q))          \
    ) __name (                                        \
      .clk_i   ( __clk   ),                           \
      .rst_ni  ( __rst_n ),                           \
      .state_i ( __d     ),                           \
      .state_o (         )                            \
    );                                                \
    `PRIM_FLOP_A(__d, __q, __resval, __clk, __rst_n)  \
    `ASSERT(``__name``_A, __q === ``__name``.state_o) \
  `else                                               \
    prim_sparse_fsm_flop #(                           \
      .StateEnumT(__type),                            \
      .Width($bits(__type)),                          \
      .ResetValue($bits(__type)'(__resval)),          \
      .EnableAlertTriggerSVA(__alert_trigger_sva_en)  \
    ) __name (                                        \
      .clk_i   ( __clk   ),                           \
      .rst_ni  ( __rst_n ),                           \
      .state_i ( __d     ),                           \
      .state_o ( __q     )                            \
    );                                                \
  `endif
`endif 
`endif 
module TopModule
  import keymgr_pkg::*;
  import keymgr_dpe_pkg::*;
  import keymgr_dpe_reg_pkg::*;
#(
  parameter logic [NumAlerts-1:0] AlertAsyncOn = {NumAlerts{1'b1}},
  
  parameter int unsigned AlertSkewCycles       = 1,
  parameter bit KmacEnMasking                  = 1'b1,
  parameter lfsr_seed_t RndCnstLfsrSeed        = RndCnstLfsrSeedDefault,
  parameter lfsr_perm_t RndCnstLfsrPerm        = RndCnstLfsrPermDefault,
  parameter rand_perm_t RndCnstRandPerm        = RndCnstRandPermDefault,
  parameter seed_t RndCnstRevisionSeed         = RndCnstRevisionSeedDefault,
  parameter seed_t RndCnstSoftOutputSeed       = RndCnstSoftOutputSeedDefault,
  parameter seed_t RndCnstHardOutputSeed       = RndCnstHardOutputSeedDefault,
  parameter seed_t RndCnstNoneSeed             = RndCnstNoneSeedDefault,
  parameter seed_t RndCnstAesSeed              = RndCnstAesSeedDefault,
  parameter seed_t RndCnstOtbnSeed             = RndCnstOtbnSeedDefault,
  parameter seed_t RndCnstKmacSeed             = RndCnstKmacSeedDefault
) (
  input clk_i,
  input rst_ni,
  input rst_shadowed_ni,
  input clk_edn_i,
  input rst_edn_ni,
  
  input  tlul_pkg::tl_h2d_t tl_i,
  output tlul_pkg::tl_d2h_t tl_o,
  
  output hw_key_req_t aes_key_o,
  output hw_key_req_t kmac_key_o,
  output otbn_key_req_t otbn_key_o,
  
  output kmac_pkg::app_req_t kmac_data_o,
  input  kmac_pkg::app_rsp_t kmac_data_i,
  
  
  
  
  input kmac_en_masking_i,
  
  
  input lc_ctrl_pkg::lc_tx_t lc_keymgr_en_i,
  input lc_ctrl_pkg::lc_keymgr_div_t lc_keymgr_div_i,
  input otp_ctrl_pkg::otp_keymgr_key_t otp_key_i,
  input otp_ctrl_pkg::otp_device_id_t otp_device_id_i,
  
  output edn_pkg::edn_req_t edn_o,
  input edn_pkg::edn_rsp_t edn_i,
  
  input rom_ctrl_pkg::keymgr_data_t [NumRomDigestInputs-1:0] rom_digest_i,
  
  output logic intr_op_done_o,
  input  prim_alert_pkg::alert_rx_t [keymgr_reg_pkg::NumAlerts-1:0] alert_rx_i,
  output prim_alert_pkg::alert_tx_t [keymgr_reg_pkg::NumAlerts-1:0] alert_tx_o
);
  `ASSERT_INIT(DpeAdvDataWidth_A, DpeAdvDataWidth <= KDFMaxWidth)
  `ASSERT_INIT(GenDataWidth_A, GenDataWidth <= KDFMaxWidth)
  `ASSERT_INIT(OutputKeyDiff_A, RndCnstHardOutputSeed != RndCnstSoftOutputSeed)
  import prim_mubi_pkg::mubi4_test_true_strict;
  import prim_mubi_pkg::mubi4_test_false_strict;
  import lc_ctrl_pkg::lc_tx_test_true_strict;
  import lc_ctrl_pkg::lc_tx_test_false_loose;
  import lc_ctrl_pkg::lc_tx_t;
  
  
  
  localparam int TotalSeedWidth = KeyWidth * 7;
  seed_t revision_seed;
  seed_t soft_output_seed;
  seed_t hard_output_seed;
  seed_t aes_seed;
  seed_t otbn_seed;
  seed_t kmac_seed;
  seed_t none_seed;
  localparam logic [TotalSeedWidth-1:0] RndConstSeed = {RndCnstRevisionSeed,
                                                        RndCnstSoftOutputSeed,
                                                        RndCnstHardOutputSeed,
                                                        RndCnstAesSeed,
                                                        RndCnstOtbnSeed,
                                                        RndCnstKmacSeed,
                                                        RndCnstNoneSeed};
  prim_sec_anchor_const #(
    .Width(TotalSeedWidth),
    .ConstVal(RndConstSeed)
  ) u_seed_anchor_const (
    .out_o({revision_seed,
            soft_output_seed,
            hard_output_seed,
            aes_seed,
            otbn_seed,
            kmac_seed,
            none_seed})
  );
  
  keymgr_dpe_reg2hw_t reg2hw;
  keymgr_dpe_hw2reg_t hw2reg;
  logic regfile_intg_err;
  logic shadowed_storage_err;
  logic shadowed_update_err;
  
  
  
  
  keymgr_dpe_reg_top u_reg (
    .clk_i,
    .rst_ni,
    .rst_shadowed_ni,
    .tl_i,
    .tl_o,
    .reg2hw,
    .hw2reg,
    .shadowed_storage_err_o (shadowed_storage_err),
    .shadowed_update_err_o  (shadowed_update_err),
    .intg_err_o             (regfile_intg_err)
  );
  
  
  
  
  lc_tx_t [KeymgrDpeEnLast-1:0] lc_keymgr_en;
  prim_lc_sync #(
    .NumCopies(int'(KeymgrDpeEnLast))
  ) u_lc_keymgr_en_sync (
    .clk_i,
    .rst_ni,
    .lc_en_i(lc_keymgr_en_i),
    .lc_en_o(lc_keymgr_en)
  );
  
  
  
  
  
  
  
  
  
  
  
  logic lfsr_en;
  logic seed_en;
  logic [LfsrWidth-1:0] seed;
  logic reseed_req;
  logic reseed_ack;
  logic reseed_done;
  logic reseed_cnt_err;
  keymgr_reseed_ctrl u_reseed_ctrl (
    .clk_i,
    .rst_ni,
    .clk_edn_i,
    .rst_edn_ni,
    .reseed_req_i(reseed_req),
    .reseed_ack_o(reseed_ack),
    .reseed_done_o(reseed_done),
    .reseed_interval_i(reg2hw.reseed_interval_shadowed.q),
    .edn_o,
    .edn_i,
    .lfsr_en_i(lfsr_en),
    .seed_en_o(seed_en),
    .seed_o(seed),
    .cnt_err_o(reseed_cnt_err)
  );
  logic [63:0] lfsr;
  logic ctrl_lfsr_en, data_lfsr_en, sideload_lfsr_en;
  assign lfsr_en = ctrl_lfsr_en | data_lfsr_en | sideload_lfsr_en;
  prim_lfsr #(
    .LfsrDw(LfsrWidth),
    .StateOutDw(LfsrWidth),
    .DefaultSeed(RndCnstLfsrSeed),
    .StatePermEn(1'b1),
    .StatePerm(RndCnstLfsrPerm),
    .NonLinearOut(1'b1)
  ) u_lfsr (
    .clk_i,
    .rst_ni,
    .lfsr_en_i(lfsr_en),
    .seed_en_i(seed_en),
    .seed_i(seed),
    .entropy_i('0),
    .state_o(lfsr)
  );
  `ASSERT_INIT(LfsrWidth_A, LfsrWidth == 64)
  logic [Shares-1:0][RandWidth-1:0] ctrl_rand;
  logic [Shares-1:0][RandWidth-1:0] data_rand;
  assign ctrl_rand[0] = lfsr[63:32];
  assign ctrl_rand[1] = perm_data(lfsr[31:0], RndCnstRandPerm);
  assign data_rand[0] = lfsr[31:0];
  assign data_rand[1] = perm_data(lfsr[63:32], RndCnstRandPerm);
  
  
  
  prim_mubi_pkg::mubi4_t hw_key_sel;
  logic adv_en, id_en, gen_en;
  logic wipe_key;
  hw_key_req_t kmac_key;
  logic op_done;
  logic init;
  logic data_valid;
  logic data_hw_en;
  logic data_sw_en;
  logic kmac_done;
  logic kmac_input_invalid;
  logic kmac_cmd_err;
  logic kmac_fsm_err;
  logic kmac_op_err;
  logic kmac_done_err;
  logic [Shares-1:0][kmac_pkg::AppDigestW-1:0] kmac_data;
  logic [Shares-1:0][KeyWidth-1:0] kmac_data_truncated;
  logic [ErrLastPos-1:0] err_code;
  logic [FaultLastPos-1:0] fault_code;
  logic unlock_after_advance;
  logic sideload_fsm_err;
  logic sideload_sel_err;
  logic key_version_vld;
  for (genvar i = 0; i < Shares; i++) begin : gen_truncate_data
    assign kmac_data_truncated[i] = kmac_data[i][KeyWidth-1:0];
  end
  hw_key_req_t root_key;
  assign root_key.key = '{otp_key_i.creator_root_key_share1,
                          otp_key_i.creator_root_key_share0};
  prim_flop_2sync # (
    .Width(1)
  ) u_key_valid_sync (
    .clk_i,
    .rst_ni,
    .d_i(otp_key_i.creator_root_key_share0_valid &
         otp_key_i.creator_root_key_share1_valid),
    .q_o(root_key.valid)
  );
  keymgr_dpe_slot_t active_key_slot;
  logic op_start;
  assign op_start = reg2hw.start.q;
  logic invalid_advance;
  keymgr_dpe_ctrl u_ctrl (
    .clk_i,
    .rst_ni,
    .en_i(lc_tx_test_true_strict(lc_keymgr_en[KeymgrDpeEnCtrl])),
    .regfile_intg_err_i(regfile_intg_err),
    .shadowed_update_err_i(shadowed_update_err),
    .shadowed_storage_err_i(shadowed_storage_err),
    .reseed_cnt_err_i(reseed_cnt_err),
    .sideload_sel_err_i(sideload_sel_err),
    .sideload_fsm_err_i(sideload_fsm_err),
    .prng_reseed_req_o(reseed_req),
    .prng_reseed_ack_i(reseed_ack),
    .prng_reseed_done_i(reseed_done),
    .prng_en_o(ctrl_lfsr_en),
    .entropy_i(ctrl_rand),
    .op_i(keymgr_dpe_ops_e'(reg2hw.control_shadowed.operation.q)),
    .load_key_lock_i(reg2hw.load_key_lock.q),
    
    
    .slot_src_sel_i(keymgr_dpe_slot_idx_e'(reg2hw.control_shadowed.slot_src_sel.q)),
    .slot_dst_sel_i(keymgr_dpe_slot_idx_e'(reg2hw.control_shadowed.slot_dst_sel.q)),
    .slot_policy_i(keymgr_dpe_policy_t'(reg2hw.slot_policy)),
    .max_key_version_i(reg2hw.max_key_ver_shadowed),
    .key_version_i(reg2hw.key_version),
    .key_version_vld_o(key_version_vld),
    .op_start_i(op_start),
    .op_done_o(op_done),
    .init_o(init),
    .unlock_after_advance_o(unlock_after_advance),
    .status_o(hw2reg.op_status.d),
    .fault_o(fault_code),
    .error_o(err_code),
    .data_hw_en_o(data_hw_en),
    .data_sw_en_o(data_sw_en),
    .data_valid_o(data_valid),
    .working_state_o(hw2reg.working_state.d),
    .root_key_i(root_key),
    .hw_sel_o(hw_key_sel),
    .wipe_key_o(wipe_key),
    .adv_en_o(adv_en),
    .gen_en_o(gen_en),
    .key_o(kmac_key),
    .active_key_slot_o(active_key_slot),
    .invalid_advance_o(invalid_advance),
    .kmac_done_i(kmac_done),
    .kmac_input_invalid_i(kmac_input_invalid),
    .kmac_fsm_err_i(kmac_fsm_err),
    .kmac_op_err_i(kmac_op_err),
    .kmac_done_err_i(kmac_done_err),
    .kmac_cmd_err_i(kmac_cmd_err),
    .kmac_data_i(kmac_data_truncated)
  );
  assign hw2reg.start.d  = '0;
  assign hw2reg.start.de = op_done;
  
  assign hw2reg.op_status.de = op_start;
  
  assign hw2reg.working_state.de = 1'b1;
  logic cfg_regwen;
  
  keymgr_cfg_en u_cfgen (
    .clk_i,
    .rst_ni,
    .init_i(1'b1), 
    .en_i(lc_tx_test_true_strict(lc_keymgr_en[KeymgrDpeEnCfg])),
    .set_i(op_start & op_done),
    .clr_i(op_start),
    .out_o(cfg_regwen)
  );
  assign hw2reg.cfg_regwen.d = cfg_regwen;
  logic sw_binding_clr;
  logic sw_binding_regwen;
  logic slot_policy_clr;
  logic slot_policy_regwen;
  logic max_key_ver_clr;
  logic max_key_ver_regwen;
  
  assign sw_binding_clr = reg2hw.sw_binding_regwen.qe & ~reg2hw.sw_binding_regwen.q;
  assign slot_policy_clr = reg2hw.slot_policy_regwen.qe & ~reg2hw.slot_policy_regwen.q;
  assign max_key_ver_clr = reg2hw.max_key_ver_regwen.qe & ~reg2hw.max_key_ver_regwen.q;
  
  
  keymgr_cfg_en #(
    .NonInitClr(1'b1)  
  ) u_sw_binding_regwen (
    .clk_i,
    .rst_ni,
    
    .init_i(init),
    .en_i(lc_tx_test_true_strict(lc_keymgr_en[KeymgrDpeEnBinding])),
    .set_i(unlock_after_advance),
    .clr_i(sw_binding_clr),
    .out_o(sw_binding_regwen)
  );
  
  
  keymgr_cfg_en #(
    .NonInitClr(1'b1)  
  ) u_slot_policy_regwen (
    .clk_i,
    .rst_ni,
    
    .init_i(init),
    .en_i(lc_tx_test_true_strict(lc_keymgr_en[KeymgrDpeEnBinding])),
    .set_i(unlock_after_advance),
    .clr_i(slot_policy_clr),
    .out_o(slot_policy_regwen)
  );
  
  
  keymgr_cfg_en #(
    .NonInitClr(1'b1)  
  ) u_max_key_ver_regwen (
    .clk_i,
    .rst_ni,
    
    .init_i(init),
    .en_i(lc_tx_test_true_strict(lc_keymgr_en[KeymgrDpeEnBinding])),
    .set_i(unlock_after_advance),
    .clr_i(max_key_ver_clr),
    .out_o(max_key_ver_regwen)
  );
  assign hw2reg.sw_binding_regwen.d = sw_binding_regwen & cfg_regwen;
  assign hw2reg.slot_policy_regwen.d = slot_policy_regwen & cfg_regwen;
  assign hw2reg.max_key_ver_regwen.d = max_key_ver_regwen & cfg_regwen;
  
  
  
  
  logic rom_digest_vld;
  logic [2 ** DpeBootStagesWidth-1:0][DpeAdvDataWidth-1:0] adv_matrix;
  logic [2 ** DpeBootStagesWidth-1:0] adv_dvalid;
  logic [GenDataWidth-1:0] gen_in;
  
  localparam int GenLfsrCopies = GenDataWidth / 32;
  
  logic creator_seed_vld;
  logic owner_seed_vld;
  logic devid_vld;
  logic health_state_vld;
  
  logic [SwBindingWidth-1:0] sw_binding;
  assign sw_binding = reg2hw.sw_binding;
  
  logic [KeyWidth*NumRomDigestInputs-1:0] rom_digests;
  always_comb begin
    rom_digests = '0;
    for (int k = 0; k < NumRomDigestInputs; k++) begin
      rom_digests[KeyWidth*k +: KeyWidth] = rom_digest_i[k].data;
    end
  end
  
  
  logic [KeyWidth-1:0] creator_seed;
  logic unused_creator_seed;
  assign unused_creator_seed = ^{otp_key_i.creator_seed_valid};
  assign creator_seed = otp_key_i.creator_seed;
  
  logic [KeyWidth-1:0] owner_seed;
  logic unused_owner_seed;
  assign unused_owner_seed = ^{otp_key_i.owner_seed_valid};
  assign owner_seed = otp_key_i.owner_seed;
  always_comb begin : gen_adv_matrix_all
    
    adv_matrix = {(2 ** DpeBootStagesWidth){DpeAdvDataWidth'(sw_binding)}};
    adv_dvalid = {(2 ** DpeBootStagesWidth){1'b1}};
    if (reg2hw.control_shadowed.sw_binding_only.q == 1'b0) begin
      
      adv_matrix[BootStageCreator] = DpeAdvDataWidth'({sw_binding,
                                                      revision_seed,
                                                      otp_device_id_i,
                                                      lc_keymgr_div_i,
                                                      rom_digests,
                                                      creator_seed});
      adv_dvalid[BootStageCreator] = creator_seed_vld &
                                    devid_vld         &
                                    health_state_vld  &
                                    rom_digest_vld;
      adv_matrix[BootStageOwner] = DpeAdvDataWidth'({sw_binding,owner_seed});
      adv_dvalid[BootStageOwner] = owner_seed_vld;
    end
  end
  
  logic [KeyWidth-1:0] output_key;
  keymgr_key_dest_e dest_sel;
  logic [KeyWidth-1:0] dest_seed;
  assign dest_sel = keymgr_key_dest_e'(reg2hw.control_shadowed.dest_sel.q);
  assign dest_seed = dest_sel == Aes  ? aes_seed  :
                       dest_sel == Kmac ? kmac_seed :
                       dest_sel == Otbn ? otbn_seed : none_seed;
  assign output_key = mubi4_test_true_strict(hw_key_sel) ? hard_output_seed :
                      soft_output_seed;
  assign gen_in = active_key_slot.valid ? {reg2hw.key_version,
                                           reg2hw.salt,
                                           dest_seed,
                                           output_key} : {GenLfsrCopies{lfsr[31:0]}};
  hw_key_req_t curr_active_key;
  assign curr_active_key = '{
    valid: active_key_slot.valid,
    key: active_key_slot.key
  };
  
  logic key_vld;
  
  
  keymgr_input_checks #(
    .KmacEnMasking(KmacEnMasking),
    .NumRomDigestInputs(NumRomDigestInputs)
  ) u_checks (
    .rom_digest_i,
    
    .cur_max_key_version_i('0),
    .key_version_i('0),
    .creator_seed_i(creator_seed),
    .owner_seed_i(owner_seed),
    .key_i(curr_active_key),
    .devid_i(otp_device_id_i),
    .health_state_i(HealthStateWidth'(lc_keymgr_div_i)),
    .creator_seed_vld_o(creator_seed_vld),
    .owner_seed_vld_o(owner_seed_vld),
    .devid_vld_o(devid_vld),
    .health_state_vld_o(health_state_vld),
    
    .key_version_vld_o(),
    .key_vld_o(key_vld),
    .rom_digest_vld_o(rom_digest_vld)
  );
  assign hw2reg.debug.invalid_creator_seed.d  = ~creator_seed_vld;
  assign hw2reg.debug.invalid_owner_seed.d    = ~owner_seed_vld;
  assign hw2reg.debug.invalid_dev_id.d        = ~devid_vld;
  assign hw2reg.debug.invalid_health_state.d  = ~health_state_vld;
  assign hw2reg.debug.invalid_key_version.d   = ~key_version_vld;
  assign hw2reg.debug.invalid_key.d           = ~key_vld;
  assign hw2reg.debug.invalid_digest.d        = ~rom_digest_vld;
  assign hw2reg.debug.invalid_root_key.d      = ~root_key.valid;
  assign hw2reg.debug.inactive_lc_en.d        = lc_tx_test_false_loose(
                                                  lc_keymgr_en[KeymgrDpeEnDebug]);
  
  
  logic is_creator_boot_stage, is_owner_boot_stage;
  assign is_creator_boot_stage = active_key_slot.boot_stage == BootStageCreator;
  assign is_owner_boot_stage   = active_key_slot.boot_stage == BootStageOwner;
  assign hw2reg.debug.invalid_creator_seed.de = adv_en & is_creator_boot_stage;
  assign hw2reg.debug.invalid_dev_id.de       = adv_en & is_creator_boot_stage;
  assign hw2reg.debug.invalid_health_state.de = adv_en & is_creator_boot_stage;
  assign hw2reg.debug.invalid_digest.de       = adv_en & is_creator_boot_stage;
  
  assign hw2reg.debug.invalid_owner_seed.de    = adv_en & is_owner_boot_stage;
  
  
  assign hw2reg.debug.invalid_key_version.de   = gen_en;
  assign hw2reg.debug.invalid_key.de           = adv_en | gen_en;
  assign hw2reg.debug.invalid_root_key.de      = init;
  assign hw2reg.debug.inactive_lc_en.de        = 1'b1;
  
  
  
  
  
  
  logic [3:0] invalid_data;
  assign invalid_data[OpAdvance]  = ~key_vld | invalid_advance |
                                    ~adv_dvalid[active_key_slot.boot_stage];
  
  
  assign invalid_data[OpGenId] = 1'b0;
  assign invalid_data[OpGenSwOut] = ~key_vld | ~key_version_vld;
  assign invalid_data[OpGenHwOut] = ~key_vld | ~key_version_vld;
  
  assign id_en = 1'b0;
  keymgr_kmac_if #(
    .MaxAdvDataWidth(DpeAdvDataWidth)
  ) u_kmac_if (
    .clk_i,
    .rst_ni,
    .prng_en_o(data_lfsr_en),
    .adv_data_i(adv_matrix[active_key_slot.boot_stage]),
    
    
    .id_data_i('0),
    .gen_data_i(gen_in),
    .inputs_invalid_i(invalid_data),
    .inputs_invalid_o(kmac_input_invalid),
    .adv_en_i(adv_en),
    .id_en_i(id_en),
    .gen_en_i(gen_en),
    .done_o(kmac_done),
    .data_o(kmac_data),
    .kmac_data_o,
    .kmac_data_i,
    .entropy_i(data_rand),
    .fsm_error_o(kmac_fsm_err),
    .kmac_error_o(kmac_op_err),
    .kmac_done_error_o(kmac_done_err),
    .cmd_error_o(kmac_cmd_err)
  );
  
  
  
  
  keymgr_sideload_key_ctrl u_sideload_ctrl (
    .clk_i,
    .rst_ni,
    .init_i(init),
    .entropy_i(data_rand),
    .clr_key_i(keymgr_sideload_clr_e'(reg2hw.sideload_clear.q)),
    .wipe_key_i(wipe_key),
    .dest_sel_i(dest_sel),
    .hw_key_sel_i(hw_key_sel),
    
    .data_en_i(data_hw_en),
    .data_valid_i(data_valid),
    .key_i(kmac_key),
    .data_i(kmac_data),
    .prng_en_o(sideload_lfsr_en),
    .aes_key_o,
    .otbn_key_o,
    .kmac_key_o,
    .sideload_sel_err_o(sideload_sel_err),
    .fsm_err_o(sideload_fsm_err)
  );
  for (genvar i = 0; i < 8; i++) begin : gen_sw_assigns
    prim_mubi_pkg::mubi4_t [1:0] hw_key_sel_buf;
    prim_mubi4_sync #(
      .NumCopies(2),
      .AsyncOn(0)
    ) u_mubi_buf (
      .clk_i,
      .rst_ni,
      .mubi_i(hw_key_sel),
      .mubi_o(hw_key_sel_buf)
    );
    
    prim_sec_anchor_buf #(
     .Width(32)
    ) u_prim_buf_share0_d (
      .in_i(~data_sw_en | wipe_key ? data_rand[0] : kmac_data[0][i*32 +: 32]),
      .out_o(hw2reg.sw_share0_output[i].d)
    );
    prim_sec_anchor_buf #(
     .Width(32)
    ) u_prim_buf_share1_d (
      .in_i(~data_sw_en | wipe_key ? data_rand[1] : kmac_data[1][i*32 +: 32]),
      .out_o(hw2reg.sw_share1_output[i].d)
    );
    prim_sec_anchor_buf #(
     .Width(1)
    ) u_prim_buf_share0_de (
      .in_i(wipe_key | data_valid & mubi4_test_false_strict(hw_key_sel_buf[0])),
      .out_o(hw2reg.sw_share0_output[i].de)
    );
    prim_sec_anchor_buf #(
     .Width(1)
    ) u_prim_buf_share1_de (
      .in_i(wipe_key | data_valid & mubi4_test_false_strict(hw_key_sel_buf[1])),
      .out_o(hw2reg.sw_share1_output[i].de)
    );
  end
  
  
  
  prim_intr_hw #(.Width(1)) u_intr_op_done (
    .clk_i,
    .rst_ni,
    .event_intr_i           (op_done),
    .reg2hw_intr_enable_q_i (reg2hw.intr_enable.q),
    .reg2hw_intr_test_q_i   (reg2hw.intr_test.q),
    .reg2hw_intr_test_qe_i  (reg2hw.intr_test.qe),
    .reg2hw_intr_state_q_i  (reg2hw.intr_state.q),
    .hw2reg_intr_state_de_o (hw2reg.intr_state.de),
    .hw2reg_intr_state_d_o  (hw2reg.intr_state.d),
    .intr_o                 (intr_op_done_o)
  );
  assign hw2reg.err_code.invalid_op.d             = 1'b1;
  assign hw2reg.err_code.invalid_kmac_input.d     = 1'b1;
  assign hw2reg.err_code.invalid_shadow_update.d  = 1'b1;
  assign hw2reg.err_code.invalid_op.de            = err_code[ErrInvalidOp];
  assign hw2reg.err_code.invalid_kmac_input.de    = err_code[ErrInvalidIn];
  assign hw2reg.err_code.invalid_shadow_update.de = err_code[ErrShadowUpdate];
  assign hw2reg.fault_status.cmd.de           = fault_code[FaultKmacCmd];
  assign hw2reg.fault_status.kmac_fsm.de      = fault_code[FaultKmacFsm];
  assign hw2reg.fault_status.kmac_op.de       = fault_code[FaultKmacOp];
  assign hw2reg.fault_status.kmac_done.de     = fault_code[FaultKmacDone];
  assign hw2reg.fault_status.kmac_out.de      = fault_code[FaultKmacOut];
  assign hw2reg.fault_status.regfile_intg.de  = fault_code[FaultRegIntg];
  assign hw2reg.fault_status.shadow.de        = fault_code[FaultShadow];
  assign hw2reg.fault_status.ctrl_fsm_intg.de = fault_code[FaultCtrlFsm];
  assign hw2reg.fault_status.ctrl_fsm_chk.de  = fault_code[FaultCtrlFsmChk];
  assign hw2reg.fault_status.ctrl_fsm_cnt.de  = fault_code[FaultCtrlCnt];
  assign hw2reg.fault_status.reseed_cnt.de    = fault_code[FaultReseedCnt];
  assign hw2reg.fault_status.side_ctrl_fsm.de = fault_code[FaultSideFsm];
  assign hw2reg.fault_status.side_ctrl_sel.de = fault_code[FaultSideSel];
  assign hw2reg.fault_status.key_ecc.de       = fault_code[FaultKeyEcc];
  assign hw2reg.fault_status.cmd.d            = 1'b1;
  assign hw2reg.fault_status.kmac_fsm.d       = 1'b1;
  assign hw2reg.fault_status.kmac_done.d      = 1'b1;
  assign hw2reg.fault_status.kmac_op.d        = 1'b1;
  assign hw2reg.fault_status.kmac_out.d       = 1'b1;
  assign hw2reg.fault_status.regfile_intg.d   = 1'b1;
  assign hw2reg.fault_status.shadow.d         = 1'b1;
  assign hw2reg.fault_status.ctrl_fsm_intg.d  = 1'b1;
  assign hw2reg.fault_status.ctrl_fsm_chk.d   = 1'b1;
  assign hw2reg.fault_status.ctrl_fsm_cnt.d   = 1'b1;
  assign hw2reg.fault_status.reseed_cnt.d     = 1'b1;
  assign hw2reg.fault_status.side_ctrl_fsm.d  = 1'b1;
  assign hw2reg.fault_status.side_ctrl_sel.d  = 1'b1;
  assign hw2reg.fault_status.key_ecc.d        = 1'b1;
  
  
  
  logic fault_errs, fault_err_req_q, fault_err_req_d, fault_err_ack;
  logic op_errs, op_err_req_q, op_err_req_d, op_err_ack;
  
  assign fault_errs = |reg2hw.fault_status;
  assign fault_err_req_d = fault_errs    ? 1'b1 :
                           fault_err_ack ? 1'b0 : fault_err_req_q;
  assign op_errs = |err_code;
  assign op_err_req_d = op_errs    ? 1'b1 :
                        op_err_ack ? 1'b0 : op_err_req_q;
  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      fault_err_req_q <= '0;
      op_err_req_q <= '0;
    end else begin
      fault_err_req_q <= fault_err_req_d;
      op_err_req_q <= op_err_req_d;
    end
  end
  logic fault_alert_test;
  assign fault_alert_test = reg2hw.alert_test.fatal_fault_err.q &
                            reg2hw.alert_test.fatal_fault_err.qe;
  prim_alert_sender #(
    .AsyncOn(AlertAsyncOn[1]),
    .SkewCycles(AlertSkewCycles),
    .IsFatal(1)
  ) u_fault_alert (
    .clk_i,
    .rst_ni,
    .alert_test_i(fault_alert_test),
    .alert_req_i(fault_err_req_q),
    .alert_ack_o(fault_err_ack),
    .alert_state_o(),
    .alert_rx_i(alert_rx_i[1]),
    .alert_tx_o(alert_tx_o[1])
  );
  logic op_err_alert_test;
  assign op_err_alert_test = reg2hw.alert_test.recov_operation_err.q &
                             reg2hw.alert_test.recov_operation_err.qe;
  prim_alert_sender #(
    .AsyncOn(AlertAsyncOn[0]),
    .SkewCycles(AlertSkewCycles),
    .IsFatal(0)
  ) u_op_err_alert (
    .clk_i,
    .rst_ni,
    .alert_test_i(op_err_alert_test),
    .alert_req_i(op_err_req_q),
    .alert_ack_o(op_err_ack),
    .alert_state_o(),
    .alert_rx_i(alert_rx_i[0]),
    .alert_tx_o(alert_tx_o[0])
  );
  
  `ASSERT_KNOWN(TlDValidKnownO_A, tl_o.d_valid)
  `ASSERT_KNOWN(TlAReadyKnownO_A, tl_o.a_ready)
  `ASSERT_KNOWN(IntrKnownO_A, intr_op_done_o)
  `ASSERT_KNOWN(AlertKnownO_A, alert_tx_o)
  `ASSERT_KNOWN(AesKeyKnownO_A,  aes_key_o)
  `ASSERT_KNOWN(KmacKeyKnownO_A, kmac_key_o)
  `ASSERT_KNOWN(OtbnKeyKnownO_A, otbn_key_o)
  `ASSERT_KNOWN(KmacDataKnownO_A, kmac_data_o)
  
  
  logic unused_kmac_en_masking;
  assign unused_kmac_en_masking = kmac_en_masking_i;
  
  
  keymgr_dpe_policy_t unused_active_policy;
  logic [KeyVersionWidth-1:0] unused_active_key_version;
  assign unused_active_policy = active_key_slot.key_policy;
  assign unused_active_key_version = active_key_slot.max_key_version;
  `ASSERT_INIT(KeyWidthEqualityCheck_A, otp_ctrl_pkg::KeyMgrKeyWidth == KeyWidth)
  `ASSERT_INIT_NET(KmacMaskCheck_A, KmacEnMasking == kmac_en_masking_i)
  
  `ASSERT_INIT(FaultCntMatch_A, FaultLastPos == AsyncFaultLastIdx + SyncFaultLastIdx)
  `ASSERT_INIT(ErrCntMatch_A, ErrLastPos == AsyncErrLastIdx + SyncErrLastIdx)
  `ASSERT_PRIM_COUNT_ERROR_TRIGGER_ALERT(CtrlCntAlertCheck_A, u_ctrl.u_cnt, alert_tx_o[1])
  `ASSERT_PRIM_COUNT_ERROR_TRIGGER_ALERT(KmacIfCntAlertCheck_A, u_kmac_if.u_cnt, alert_tx_o[1])
  `ASSERT_PRIM_COUNT_ERROR_TRIGGER_ALERT(ReseedCtrlCntAlertCheck_A, u_reseed_ctrl.u_reseed_cnt,
                                         alert_tx_o[1])
  `ASSERT_PRIM_FSM_ERROR_TRIGGER_ALERT(CtrlMainFsmCheck_A, u_ctrl.u_state_regs, alert_tx_o[1])
  `ASSERT_PRIM_FSM_ERROR_TRIGGER_ALERT(CtrlDataFsmCheck_A,
      u_ctrl.u_data_en.u_state_regs, alert_tx_o[1])
  `ASSERT_PRIM_FSM_ERROR_TRIGGER_ALERT(CtrlOpFsmCheck_A,
      u_ctrl.u_op_state.u_state_regs, alert_tx_o[1])
  `ASSERT_PRIM_FSM_ERROR_TRIGGER_ALERT(KmacIfFsmCheck_A, u_kmac_if.u_state_regs, alert_tx_o[1])
  `ASSERT_PRIM_FSM_ERROR_TRIGGER_ALERT(SideloadCtrlFsmCheck_A,
      u_sideload_ctrl.u_state_regs, alert_tx_o[1])
  
  `ASSERT_PRIM_REG_WE_ONEHOT_ERROR_TRIGGER_ALERT(RegWeOnehotCheck_A, u_reg, alert_tx_o[1])
endmodule 

`ifndef PRIM_ASSERT_SV
`define PRIM_ASSERT_SV
`define ASSERT_DEFAULT_CLK clk_i
`define ASSERT_DEFAULT_RST !rst_ni
`define PRIM_STRINGIFY(__x) `"__x`"
`define ASSERT_ERROR(__name)                                                             \
`ifdef UVM                                                                               \
  uvm_pkg::uvm_report_error("ASSERT FAILED", `PRIM_STRINGIFY(__name), uvm_pkg::UVM_NONE, \
                            `__FILE__, `__LINE__, "", 1);                                \
`else                                                                                    \
  $error("%0t: (%0s:%0d) [%m] [ASSERT FAILED] %0s", $time, `__FILE__, `__LINE__,         \
         `PRIM_STRINGIFY(__name));                                                       \
`endif
`define ASSERT_STATIC_LINT_ERROR(__name, __prop)     \
  localparam int __name = (__prop) ? 1 : 2;          \
  always_comb begin                                  \
    logic unused_assert_static_lint_error;           \
    unused_assert_static_lint_error = __name'(1'b1); \
  end
`define ASSERT_STATIC_IN_PACKAGE(__name, __prop)              \
  function automatic bit assert_static_in_package_``__name(); \
    bit unused_bit [((__prop) ? 1 : -1)];                     \
    unused_bit = '{default: 1'b0};                            \
    return unused_bit[0];                                     \
  endfunction
`ifdef VERILATOR
 `include "prim_assert_dummy_macros.svh"`elsif SYNTHESIS
 `include "prim_assert_dummy_macros.svh"`elsif YOSYS
 `include "prim_assert_yosys_macros.svh"
 `define INC_ASSERT`else
 
`define ASSERT_I(__name, __prop) \
  __name: assert (__prop)        \
    else begin                   \
      `ASSERT_ERROR(__name)      \
    end
`define ASSERT_INIT(__name, __prop)                                                  \
`ifdef FPV_ON                                                                        \
  if (!(__prop)) $fatal(2, "Fatal static assertion [%s]: (%s) is not true.",         \
                        (__name), (__prop));                                         \
`else                                                                                \
  initial begin                                                                      \
    __name: assert (__prop)                                                          \
      else begin                                                                     \
        `ASSERT_ERROR(__name)                                                        \
      end                                                                            \
  end                                                                                \
`endif
`define ASSERT_INIT_NET(__name, __prop)                                                   \
  initial begin                                                                      \
    
    
    
    #1ps;                                                                            \
    __name: assert (__prop)                                                          \
      else begin                                                                     \
        `ASSERT_ERROR(__name)                                                        \
      end                                                                            \
  end                                                                                \
`define ASSERT_FINAL(__name, __prop)                                         \
`ifndef FPV_ON                                                               \
  final begin                                                                \
    __name: assert (__prop || $test$plusargs("disable_assert_final_checks")) \
      else begin                                                             \
        `ASSERT_ERROR(__name)                                                \
      end                                                                    \
  end                                                                        \
`endif
`define ASSERT_AT_RESET(__name, __prop, __rst = `ASSERT_DEFAULT_RST)          \
  
  
  
  
  
  
  
  
  
  
`ifndef FPV_ON                                                                \
  __name: assert property (@(posedge __rst) $isunknown(__rst) || (__prop))    \
`else                                                                         \
  __name: assert property (@(posedge __rst) (__prop))                         \
`endif                                                                        \
    else begin                                                                \
      `ASSERT_ERROR(__name)                                                   \
    end
`define ASSERT_AT_RESET_AND_FINAL(__name, __prop, __rst = `ASSERT_DEFAULT_RST) \
    `ASSERT_AT_RESET(AtReset_``__name``, __prop, __rst)                        \
    `ASSERT_FINAL(Final_``__name``, __prop)
`define ASSERT(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assert property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop))       \
    else begin                                                                           \
      `ASSERT_ERROR(__name)                                                              \
    end
`define ASSERT_NEVER(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assert property (@(posedge __clk) disable iff ((__rst) !== '0) not (__prop))         \
    else begin                                                                                 \
      `ASSERT_ERROR(__name)                                                                    \
    end
`define ASSERT_KNOWN(__name, __sig, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifndef FPV_ON                                                                                \
  `ASSERT(__name, !$isunknown(__sig), __clk, __rst)                                           \
`endif
`define COVER(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: cover property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop));
`define ASSUME(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assume property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop))       \
    else begin                                                                           \
      `ASSERT_ERROR(__name)                                                              \
    end
`define ASSUME_I(__name, __prop) \
  __name: assume (__prop)        \
    else begin                   \
      `ASSERT_ERROR(__name)      \
    end
 `define INC_ASSERT
`endif
`define ASSERT_PULSE(__name, __sig, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ASSERT(__name, $rose(__sig) |=> !(__sig), __clk, __rst)
`define ASSERT_IF(__name, __prop, __enable, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ASSERT(__name, (__enable) |-> (__prop), __clk, __rst)
`define ASSERT_KNOWN_IF(__name, __sig, __enable, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifndef FPV_ON                                                                                             \
  `ASSERT_KNOWN(__name``KnownEnable, __enable, __clk, __rst)                                               \
  `ASSERT_IF(__name, !$isunknown(__sig), __enable, __clk, __rst)                                           \
`endif
`define ASSUME_FPV(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifdef FPV_ON                                                                                \
   `ASSUME(__name, __prop, __clk, __rst)                                                     \
`endif
`define ASSUME_I_FPV(__name, __prop) \
`ifdef FPV_ON                        \
   `ASSUME_I(__name, __prop)         \
`endif
`define COVER_FPV(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifdef FPV_ON                                                                               \
   `COVER(__name, __prop, __clk, __rst)                                                     \
`endif
`define ASSERT_FPV_LINEAR_FSM(__name, __state, __type, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ifdef INC_ASSERT                                                                                              \
     bit __name``_cond;                                                                                          \
     always_ff @(posedge __clk or posedge __rst) begin                                                           \
       if (__rst) begin                                                                                          \
         __name``_cond <= 0;                                                                                     \
       end else begin                                                                                            \
         __name``_cond <= 1;                                                                                     \
       end                                                                                                       \
     end                                                                                                         \
     property __name``_p;                                                                                        \
       __type initial_state;                                                                                     \
       (!$stable(__state) & __name``_cond, initial_state = $past(__state)) |->                                   \
           (__state != initial_state) until !(__name``_cond);                                                    \
     endproperty                                                                                                 \
   `ASSERT(__name, __name``_p, __clk, 0)                                                                         \
  `endif
`ifndef PRIM_ASSERT_SEC_CM_SVH
`define PRIM_ASSERT_SEC_CM_SVH
`define _SEC_CM_ALERT_MAX_CYC 30
`define ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, ERR_NAME_, CLK_, RST_) \
  `ASSERT(FpvSecCm``NAME_``,                                                                    \
          $rose(HIER_.ERR_NAME_) && !(GATE_) |-> ##[0:MAX_CYCLES_] (ERR_),                      \
          CLK_, RST_)                                                                           \
  `ifdef INC_ASSERT                                                                             \
    assign HIER_.unused_assert_connected = 1'b1;                                                \
  `endif
`define ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, ERR_NAME_)    \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, (ALERT_.alert_p), GATE_, MAX_CYCLES_, ERR_NAME_, \
                            `ASSERT_DEFAULT_CLK, `ASSERT_DEFAULT_RST)                      \
  `ASSUME_FPV(``NAME_``TriggerAfterAlertInit_S,                                            \
              $stable(rst_ni) == 0 |-> HIER_.ERR_NAME_ == 0 [*10])
`define ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_IN_, GATE_, MAX_CYCLES_, ERR_NAME_) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ALERT_IN_, GATE_, MAX_CYCLES_, ERR_NAME_,           \
                            `ASSERT_DEFAULT_CLK, `ASSERT_DEFAULT_RST)
`define ASSERT_PRIM_COUNT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_DOUBLE_LFSR_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_FSM_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, unused_err_o)
`define ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_REG_WE_ONEHOT_ERROR_TRIGGER_ALERT(NAME_, REG_TOP_HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT(NAME_, \
    REG_TOP_HIER_.u_prim_reg_we_check.u_prim_onehot_check, ALERT_, GATE_, MAX_CYCLES_)
`define ASSERT_PRIM_FIFO_SYNC_SINGLETON_ERROR_TRIGGER_ALERT(NAME, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC) \
  `ASSERT_ERROR_TRIGGER_ALERT(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_COUNT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_DOUBLE_LFSR_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_FSM_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, unused_err_o)
`define ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_REG_WE_ONEHOT_ERROR_TRIGGER_ALERT_IN(NAME_, REG_TOP_HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ALERT_IN(NAME_, \
    REG_TOP_HIER_.u_prim_reg_we_check.u_prim_onehot_check, ALERT_, GATE_, MAX_CYCLES_)
`define ASSERT_PRIM_FIFO_SYNC_SINGLETON_ERROR_TRIGGER_ALERT_IN(NAME, HIER_, ALERT_, GATE_ = 0, MAX_CYCLES_ = 2) \
  `ASSERT_ERROR_TRIGGER_ALERT_IN(NAME_, HIER_, ALERT_, GATE_, MAX_CYCLES_, err_o)
`define ASSERT_PRIM_FSM_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, unused_err_o, CLK_, RST_)
`define ASSERT_PRIM_COUNT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_DOUBLE_LFSR_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = 2, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_ERROR_TRIGGER_ERR(NAME_, HIER_, ERR_, GATE_, MAX_CYCLES_, err_o, CLK_, RST_)
`define ASSERT_PRIM_REG_WE_ONEHOT_ERROR_TRIGGER_ERR(NAME_, REG_TOP_HIER_, ERR_, GATE_ = 0, MAX_CYCLES_ = `_SEC_CM_ALERT_MAX_CYC, CLK_ = clk_i, RST_ = !rst_ni) \
  `ASSERT_PRIM_ONEHOT_ERROR_TRIGGER_ERR(NAME_, \
    REG_TOP_HIER_.u_prim_reg_we_check.u_prim_onehot_check, ERR_, GATE_, MAX_CYCLES_, CLK_, RST_)
`endif 
`ifndef PRIM_FLOP_MACROS_SV
`define PRIM_FLOP_MACROS_SV
`define PRIM_FLOP_CLK clk_i
`define PRIM_FLOP_RST rst_ni
`define PRIM_FLOP_RESVAL '0
`define PRIM_FLOP_A(__d, __q, __resval = `PRIM_FLOP_RESVAL, __clk = `PRIM_FLOP_CLK, __rst_n = `PRIM_FLOP_RST) \
  always_ff @(posedge __clk or negedge __rst_n) begin \
    if (!__rst_n) begin                               \
      __q <= __resval;                                \
    end else begin                                    \
      __q <= __d;                                     \
    end                                               \
  end
`define PRIM_FLOP_SPARSE_FSM(__name, __d, __q, __type, __resval = `PRIM_FLOP_RESVAL, __clk = `PRIM_FLOP_CLK, __rst_n = `PRIM_FLOP_RST, __alert_trigger_sva_en = 1) \
  `ifdef SIMULATION                                   \
    prim_sparse_fsm_flop #(                           \
      .StateEnumT(__type),                            \
      .Width($bits(__type)),                          \
      .ResetValue($bits(__type)'(__resval)),          \
      .EnableAlertTriggerSVA(__alert_trigger_sva_en), \
      .CustomForceName(`PRIM_STRINGIFY(__q))          \
    ) __name (                                        \
      .clk_i   ( __clk   ),                           \
      .rst_ni  ( __rst_n ),                           \
      .state_i ( __d     ),                           \
      .state_o (         )                            \
    );                                                \
    `PRIM_FLOP_A(__d, __q, __resval, __clk, __rst_n)  \
    `ASSERT(``__name``_A, __q === ``__name``.state_o) \
  `else                                               \
    prim_sparse_fsm_flop #(                           \
      .StateEnumT(__type),                            \
      .Width($bits(__type)),                          \
      .ResetValue($bits(__type)'(__resval)),          \
      .EnableAlertTriggerSVA(__alert_trigger_sva_en)  \
    ) __name (                                        \
      .clk_i   ( __clk   ),                           \
      .rst_ni  ( __rst_n ),                           \
      .state_i ( __d     ),                           \
      .state_o ( __q     )                            \
    );                                                \
  `endif
`endif 
`endif 
module keymgr_dpe_ctrl
  import keymgr_pkg::*;
  import keymgr_dpe_pkg::*;
  import keymgr_dpe_reg_pkg::*;
(
  input clk_i,
  input rst_ni,
  
  
  input en_i,
  
  input regfile_intg_err_i,
  input shadowed_update_err_i,
  input shadowed_storage_err_i,
  input reseed_cnt_err_i,
  input sideload_sel_err_i,
  input sideload_fsm_err_i,
  
  input op_start_i,
  input keymgr_dpe_ops_e op_i,
  input load_key_lock_i,
  input [DpeNumSlotsWidth-1:0] slot_src_sel_i,
  input [DpeNumSlotsWidth-1:0] slot_dst_sel_i,
  input keymgr_dpe_policy_t slot_policy_i,
   
   
  input [KeyVersionWidth-1:0] max_key_version_i,
  input [KeyVersionWidth-1:0] key_version_i,
  output key_version_vld_o,
  output logic op_done_o,
  output keymgr_op_status_e status_o,
  output logic [ErrLastPos-1:0] error_o,
  output logic [FaultLastPos-1:0] fault_o,
  output logic data_hw_en_o,
  output logic data_sw_en_o,
  
  
  
  output logic data_valid_o,
  output logic wipe_key_o,
  output keymgr_dpe_exposed_working_state_e working_state_o,
  output logic unlock_after_advance_o,
  output logic init_o,
  
  input hw_key_req_t root_key_i,
  
  
  output prim_mubi_pkg::mubi4_t hw_sel_o,
  
  output logic adv_en_o,
  output logic gen_en_o,
  output hw_key_req_t key_o,
  output keymgr_dpe_slot_t active_key_slot_o,
  output invalid_advance_o,
  input kmac_done_i,
  input kmac_input_invalid_i, 
  input kmac_fsm_err_i, 
  input kmac_op_err_i,  
  input kmac_done_err_i,
  input kmac_cmd_err_i, 
  input [Shares-1:0][KeyWidth-1:0] kmac_data_i,
  
  input [Shares-1:0][RandWidth-1:0] entropy_i,
  input prng_reseed_done_i,
  input prng_reseed_ack_i,
  output logic prng_reseed_req_o,
  output logic prng_en_o
);
  localparam int EntropyWidth = LfsrWidth / 2;
  localparam int EntropyRounds = KeyWidth / EntropyWidth;
  localparam int EntropyRndWidth = prim_util_pkg::vbits(EntropyRounds);
  keymgr_dpe_working_state_e state_q, state_d;
  
  always_comb begin
    unique case (state_q)
      StCtrlDpeReset,
      StCtrlDpeEntropyReseed,
      StCtrlDpeRandom,
      StCtrlDpeRootKey:   working_state_o = StWorkDpeReset;
      StCtrlDpeAvailable: working_state_o = StWorkDpeAvailable;
      StCtrlDpeWipe,
      StCtrlDpeDisabling,
      StCtrlDpeDisabled:  working_state_o = StWorkDpeDisabled;
      default:            working_state_o = StWorkDpeInvalid;
    endcase
  end
  logic [EntropyRndWidth-1:0] cnt;
  keymgr_dpe_slot_t [DpeNumSlots-1:0] key_slots_q;
  keymgr_dpe_slot_t [DpeNumSlots-1:0] key_slots_d;
  
  logic invalid_kmac_out;
  logic invalid_op;
  logic cnt_err;
  
  logic state_intg_err_q, state_intg_err_d;
  
  logic gen_key_op;
  assign gen_key_op = (op_i == OpDpeGenSwOut) | (op_i == OpDpeGenHwOut);
  
  
  
  logic advance_cmd;
  logic disable_cmd;
  logic gen_hw_key_cmd;
  assign advance_cmd    = op_start_i & (op_i == OpDpeAdvance)  & en_i;
  assign gen_hw_key_cmd = op_start_i & (op_i == OpDpeGenHwOut) & en_i;
  assign disable_cmd    = op_start_i & (op_i == OpDpeDisable)  & en_i;
  
  
  
  
  logic op_req;
  logic op_ack;
  logic op_update;
  logic op_busy;
  logic fsm_at_disabled;
  logic fsm_at_invalid;
  logic adv_req, gen_req, erase_req, dis_req, load_req;
  assign adv_req   = op_req & (op_i == OpDpeAdvance);
  assign gen_req   = op_req & gen_key_op;
  assign erase_req = op_req & (op_i == OpDpeErase);
  assign dis_req   = op_req & (op_i == OpDpeDisable);
  assign load_req  = op_req & (op_i == OpDpeLoadRootKey);
  
  
  
  
  logic [SyncErrLastIdx-1:0] sync_err;
  logic [SyncFaultLastIdx-1:0] sync_fault;
  logic [AsyncFaultLastIdx-1:0] async_fault;
  logic op_err;
  logic op_fault_err;
  
  assign unlock_after_advance_o = adv_req & op_ack & ~(op_err | op_fault_err);
  
  
  
  assign invalid_kmac_out = (op_update | op_ack) &
                            (~valid_data_chk(kmac_data_i[0]) |
                            ~valid_data_chk(kmac_data_i[1]));
  
  
  assign op_err = |sync_err;
  assign op_fault_err = |{sync_fault, async_fault};
  
  
  
  
  keymgr_dpe_key_update_e update_sel, op_update_sel;
  
  logic wipe_req;
  logic random_req;
  logic random_ack;
  
  assign update_sel = wipe_req                         ? SlotWipeAll        :
                      (state_q == StCtrlDpeRandom)     ? SlotDestRandomize  :
                      init_o & en_i & root_key_i.valid ? SlotLoadRoot       : op_update_sel;
  
  
  
  
  assign op_update_sel = op_update & op_fault_err               ? SlotWipeAll          :
                         op_update & dis_req                    ? SlotWipeInternalOnly :
                         op_update & (op_err | fsm_at_disabled) ? SlotUpdateIdle       :
                         op_update & adv_req                    ? SlotLoadFromKmac     :
                         op_update & load_req                   ? SlotLoadRoot         :
                         op_update & erase_req                  ? SlotErase            :
                         SlotUpdateIdle;
  
  
  
  
  
  logic [1:0] prng_en_dis_inv_d, prng_en_dis_inv_q;
  logic prng_en_dis_inv_set;
  assign prng_en_dis_inv_d =
      prng_en_dis_inv_set ? 2'b11 :
      prng_reseed_done_i  ? {1'b0, prng_en_dis_inv_q[1]} : prng_en_dis_inv_q;
  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      prng_en_dis_inv_q <= '0;
    end else begin
      prng_en_dis_inv_q <= prng_en_dis_inv_d;
    end
  end
  assign prng_en_o = random_req | wipe_req | prng_en_dis_inv_q[0];
  
  
  
  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      state_intg_err_q <= '0;
    end else begin
      state_intg_err_q <= state_intg_err_d;
    end
  end
  
  
  
  assign key_o.valid = adv_req || gen_req;
  
  
  logic release_real_key;
  assign release_real_key = active_key_slot_o.valid && !invalid_op &&
                            (adv_req || gen_req);
  for (genvar i = 0; i < Shares; i++) begin : gen_key_out_assign
    assign key_o.key[i] = release_real_key ?
                          active_key_slot_o.key[i] :
                          {EntropyRounds{entropy_i[i]}};
  end
  
  
  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      
      key_slots_q <= '0;
    end else begin
      key_slots_q <= key_slots_d;
    end
  end
  keymgr_dpe_policy_t active_slot_policy;
  assign active_key_slot_o      = key_slots_q[slot_src_sel_i];
  assign active_slot_policy     = active_key_slot_o.key_policy;
  assign data_valid_o = op_ack & gen_key_op & ~invalid_op;
  assign wipe_key_o = update_sel == SlotWipeAll;
  logic destination_slot_valid;
  assign destination_slot_valid = key_slots_q[slot_dst_sel_i].valid;
  
  
  
  always_comb begin
    key_slots_d = key_slots_q;
    unique case (update_sel)
      
      
      
      SlotDestRandomize: begin
        key_slots_d[slot_dst_sel_i] = '0;
        for (int j = 0; j < Shares; j++) begin
          
          key_slots_d[slot_dst_sel_i].key[j][cnt*EntropyWidth +: EntropyWidth] = entropy_i[0];
        end
      end
      
      
      SlotLoadRoot: begin
        key_slots_d[slot_dst_sel_i].valid = 1;
        key_slots_d[slot_dst_sel_i].boot_stage = BootStageCreator;
        key_slots_d[slot_dst_sel_i].key[0] ^= root_key_i.key[0];
        key_slots_d[slot_dst_sel_i].key[1] ^= root_key_i.key[1];
        key_slots_d[slot_dst_sel_i].max_key_version = max_key_version_i;
        key_slots_d[slot_dst_sel_i].key_policy = DEFAULT_UDS_POLICY;
      end
      
      
      SlotLoadFromKmac: begin
        
        key_slots_d[slot_dst_sel_i].valid = 1;
        key_slots_d[slot_dst_sel_i].key = kmac_data_i;
        key_slots_d[slot_dst_sel_i].max_key_version = max_key_version_i;
        key_slots_d[slot_dst_sel_i].boot_stage =
          (active_key_slot_o.boot_stage == BootStageCreator) ? BootStageOwner : BootStageRuntime;
        key_slots_d[slot_dst_sel_i].key_policy = slot_policy_i;
      end
      
      
      
      
      
      
      
      SlotErase: begin
        key_slots_d[slot_dst_sel_i] = '0;
        for (int j = 0; j < Shares; j++) begin
          
          key_slots_d[slot_dst_sel_i].key[j][cnt*EntropyWidth +: EntropyWidth] = entropy_i[0];
        end
      end
      
      
      
      
      SlotWipeAll,
      SlotWipeInternalOnly: begin
        for (int i = 0; i < DpeNumSlots; i++) begin
          
          key_slots_d[i] = '0;
          for (int j = 0; j < Shares; j++) begin
            key_slots_d[i].key[j] = {EntropyRounds{entropy_i[j]}};
          end
        end
      end
      default:;
    endcase 
  end
  
  prim_count #(
    .Width(EntropyRndWidth)
  ) u_cnt (
    .clk_i,
    .rst_ni,
    .clr_i(op_ack | random_ack),
    .set_i('0),
    .set_cnt_i('0),
    .incr_en_i(op_update | random_req),
    .decr_en_i(1'b0),
    .step_i(EntropyRndWidth'(1'b1)),
    .commit_i(1'b1),
    .cnt_o(cnt),
    .cnt_after_commit_o(),
    .err_o(cnt_err)
  );
  prim_mubi4_sender u_hw_sel (
    .clk_i,
    .rst_ni,
    .mubi_i (prim_mubi_pkg::mubi4_bool_to_mubi(gen_hw_key_cmd)),
    .mubi_o (hw_sel_o)
  );
  
  
  assign op_done_o = op_req ? op_ack : (init_o | invalid_op);
  
  
  
  
  logic invalid_advance;
  logic invalid_erase;
  logic invalid_gen;
  logic invalid_load;
  
  
  
  logic inv_state;
  assign inv_state = |fault_o;
  
  `PRIM_FLOP_SPARSE_FSM(u_state_regs, state_d, state_q, keymgr_dpe_working_state_e, StCtrlDpeReset)
  
  
  
  always_comb begin
    
    state_d = state_q;
    
    
    
    
    
    op_req = 1'b0;
    
    random_req = 1'b0;
    random_ack = 1'b0;
    
    wipe_req = 1'b0;
    
    invalid_op = 1'b0;
    
    prng_en_dis_inv_set = 1'b0;
    
    prng_reseed_req_o = 1'b0;
    
    init_o = 1'b0;
    
    
    state_intg_err_d = state_intg_err_q;
    unique case (state_q)
      
      StCtrlDpeReset: begin
        
        
        invalid_op = op_start_i & (~en_i | en_i & (op_i != OpDpeAdvance));
        
        if (inv_state) begin
          state_d = StCtrlDpeInvalid;
          prng_en_dis_inv_set = 1'b1;
        end else if (advance_cmd) begin
          state_d = StCtrlDpeEntropyReseed;
        end
      end
      
      StCtrlDpeEntropyReseed: begin
        prng_reseed_req_o = 1'b1;
        
        
        invalid_op = ~en_i;
        if (!en_i) begin
          state_d = StCtrlDpeInvalid;
          prng_en_dis_inv_set = 1'b1;
        end else if (prng_reseed_ack_i) begin
          state_d = StCtrlDpeRandom;
        end
      end
      
      
      
      
      StCtrlDpeRandom: begin
        random_req = 1'b1;
        
        
        invalid_op = ~en_i;
        if (!en_i) begin
          state_d = StCtrlDpeInvalid;
          prng_en_dis_inv_set = 1'b1;
        end else if (int'(cnt) == EntropyRounds - 1) begin
          random_ack = 1'b1;
          state_d = StCtrlDpeRootKey;
        end
      end
      
      StCtrlDpeRootKey: begin
        
        invalid_op = ~en_i;
        
        
        init_o = 1'b1;
        
        if (!en_i | inv_state | ~root_key_i.valid) begin
          state_d = StCtrlDpeInvalid;
          prng_en_dis_inv_set = 1'b1;
        end else begin
          state_d = StCtrlDpeAvailable;
        end
      end
      
      
      StCtrlDpeAvailable: begin
        op_req = op_start_i;
        
        invalid_op = invalid_advance |
                     invalid_erase   |
                     invalid_gen     |
                     invalid_load    |
                     (~en_i & op_start_i);
        
        
        if (!en_i | inv_state) begin
          state_d = StCtrlDpeWipe;
        end else if (disable_cmd) begin
          state_d = StCtrlDpeDisabling;
        end
      end
      
      
      
      
      
      StCtrlDpeWipe: begin
        wipe_req = 1'b1;
        
        
        op_req = op_busy;
        
        invalid_op = op_start_i;
        state_d = StCtrlDpeInvalid;
        prng_en_dis_inv_set = 1'b1;
      end
      StCtrlDpeDisabling: begin
        op_req = op_start_i;
        state_d = StCtrlDpeDisabled;
        prng_en_dis_inv_set = 1'b1;
      end
      
      
      
      
      StCtrlDpeDisabled: begin
        
        invalid_op = op_start_i;
        if (!en_i) begin
          state_d = StCtrlDpeWipe;
        end
      end
      
      StCtrlDpeInvalid: begin
        
        invalid_op = op_start_i;
      end
      
      default: begin
        state_intg_err_d = 1'b1;
        state_d = StCtrlDpeWipe;
      end
    endcase 
  end 
  assign fsm_at_disabled = state_q == StCtrlDpeDisabled;
  assign fsm_at_invalid  = state_q == StCtrlDpeInvalid;
  
  
  
  always_comb begin
    status_o = OpIdle;
    if (op_done_o) begin
      
      
      
      status_o = |{error_o, fault_o} ? OpDoneFail : OpDoneSuccess;
    end else if (op_start_i) begin
      status_o = OpWip;
    end
  end
  
  
  
  logic op_fsm_err;
  keymgr_dpe_op_state_ctrl u_op_state (
    .clk_i,
    .rst_ni,
    .adv_req_i(adv_req),
    .gen_req_i(gen_req),
    .erase_req_i(erase_req),
    .dis_req_i(dis_req),
    .load_req_i(load_req),
    .op_ack_o(op_ack),
    .op_busy_o(op_busy),
    .op_update_o(op_update),
    .kmac_done_i,
    .adv_en_o,
    .gen_en_o,
    .op_fsm_err_o(op_fsm_err)
  );
  
  
  
  logic data_fsm_err;
  keymgr_data_en_state u_data_en (
    .clk_i,
    .rst_ni,
    .hw_sel_i(hw_sel_o),
    .adv_en_i(adv_en_o),
    
    .id_en_i(1'b0),
    .gen_en_i(gen_en_o),
    .op_done_i(op_done_o),
    .op_start_i,
    .data_hw_en_o,
    .data_sw_en_o,
    .fsm_err_o(data_fsm_err)
  );
  
  
  
  
  assign key_version_vld_o = key_version_i <= active_key_slot_o.max_key_version;
  
  
  logic invalid_allow_child;
  assign invalid_allow_child = ~active_slot_policy.allow_child;
  
  logic invalid_src_slot;
  assign invalid_src_slot = ~active_key_slot_o.valid;
  
  
  
  
  logic invalid_retain_parent;
  assign invalid_retain_parent = active_slot_policy.retain_parent ?
                           (slot_src_sel_i == slot_dst_sel_i | destination_slot_valid) :
                           (slot_src_sel_i != slot_dst_sel_i);
  assign invalid_advance = adv_req & (invalid_allow_child |
                                      invalid_src_slot    |
                                      invalid_retain_parent);
  assign invalid_erase = erase_req & ~destination_slot_valid;
  assign invalid_gen = gen_req & (~active_key_slot_o.valid | ~key_version_vld_o);
  assign invalid_load = load_req & (~root_key_i.valid      |
                                    destination_slot_valid |
                                    load_key_lock_i);
  
  
  
  
  assign invalid_advance_o = invalid_allow_child | invalid_src_slot | invalid_retain_parent;
  
  logic unused_exportable_bit;
  assign unused_exportable_bit = active_slot_policy.exportable;
  keymgr_err u_err (
    .clk_i,
    .rst_ni,
    .invalid_op_i(invalid_op),
    
    
    .disabled_i(fsm_at_disabled),
    .invalid_i(fsm_at_invalid),
    .kmac_input_invalid_i,
    .shadowed_update_err_i,
    .kmac_op_err_i,
    .invalid_kmac_out_i(invalid_kmac_out),
    .sideload_sel_err_i,
    .kmac_cmd_err_i,
    .kmac_fsm_err_i,
    .kmac_done_err_i,
    .regfile_intg_err_i,
    .shadowed_storage_err_i,
    .ctrl_fsm_err_i(state_intg_err_q | state_intg_err_d),
    .data_fsm_err_i(data_fsm_err),
    .op_fsm_err_i(op_fsm_err),
    
    .ecc_err_i(1'b0),
    
    .state_change_err_i(1'b0),
    
    .op_state_cmd_err_i(1'b0),
    .cnt_err_i(cnt_err),
    .reseed_cnt_err_i,
    .sideload_fsm_err_i,
    .op_update_i(op_update),
    .op_done_i(op_done_o),
    .sync_err_o(sync_err),
    .async_err_o(),
    .sync_fault_o(sync_fault),
    .async_fault_o(async_fault),
    .error_o,
    .fault_o
  );
  
  
  
  
  
  
  
  
  
  `ASSERT_INIT(SameErrCnt_A, $bits(keymgr_dpe_reg2hw_fault_status_reg_t) ==
                             (SyncFaultLastIdx + AsyncFaultLastIdx))
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  `ASSERT(LoadKey_A, key_o.valid |-> op_start_i)
  
  `ASSERT(CntZero_A, $rose(op_start_i) |-> cnt == '0)
  
  `ASSERT(DataEnDis_A, op_start_i & op_done_o |=> ~data_hw_en_o && ~data_sw_en_o)
  
  
  `ASSERT(DataEn_A, data_hw_en_o | data_sw_en_o |-> gen_en_o & ~adv_en_o)
  
  `ASSERT_FPV_LINEAR_FSM(SecCmCFILinear_A, state_q, keymgr_dpe_working_state_e)
endmodule

`ifndef PRIM_ASSERT_SV
`define PRIM_ASSERT_SV
`define ASSERT_DEFAULT_CLK clk_i
`define ASSERT_DEFAULT_RST !rst_ni
`define PRIM_STRINGIFY(__x) `"__x`"
`define ASSERT_ERROR(__name)                                                             \
`ifdef UVM                                                                               \
  uvm_pkg::uvm_report_error("ASSERT FAILED", `PRIM_STRINGIFY(__name), uvm_pkg::UVM_NONE, \
                            `__FILE__, `__LINE__, "", 1);                                \
`else                                                                                    \
  $error("%0t: (%0s:%0d) [%m] [ASSERT FAILED] %0s", $time, `__FILE__, `__LINE__,         \
         `PRIM_STRINGIFY(__name));                                                       \
`endif
`define ASSERT_STATIC_LINT_ERROR(__name, __prop)     \
  localparam int __name = (__prop) ? 1 : 2;          \
  always_comb begin                                  \
    logic unused_assert_static_lint_error;           \
    unused_assert_static_lint_error = __name'(1'b1); \
  end
`define ASSERT_STATIC_IN_PACKAGE(__name, __prop)              \
  function automatic bit assert_static_in_package_``__name(); \
    bit unused_bit [((__prop) ? 1 : -1)];                     \
    unused_bit = '{default: 1'b0};                            \
    return unused_bit[0];                                     \
  endfunction
`ifdef VERILATOR
 `include "prim_assert_dummy_macros.svh"`elsif SYNTHESIS
 `include "prim_assert_dummy_macros.svh"`elsif YOSYS
 `include "prim_assert_yosys_macros.svh"
 `define INC_ASSERT`else
 
`define ASSERT_I(__name, __prop) \
  __name: assert (__prop)        \
    else begin                   \
      `ASSERT_ERROR(__name)      \
    end
`define ASSERT_INIT(__name, __prop)                                                  \
`ifdef FPV_ON                                                                        \
  if (!(__prop)) $fatal(2, "Fatal static assertion [%s]: (%s) is not true.",         \
                        (__name), (__prop));                                         \
`else                                                                                \
  initial begin                                                                      \
    __name: assert (__prop)                                                          \
      else begin                                                                     \
        `ASSERT_ERROR(__name)                                                        \
      end                                                                            \
  end                                                                                \
`endif
`define ASSERT_INIT_NET(__name, __prop)                                                   \
  initial begin                                                                      \
    
    
    
    #1ps;                                                                            \
    __name: assert (__prop)                                                          \
      else begin                                                                     \
        `ASSERT_ERROR(__name)                                                        \
      end                                                                            \
  end                                                                                \
`define ASSERT_FINAL(__name, __prop)                                         \
`ifndef FPV_ON                                                               \
  final begin                                                                \
    __name: assert (__prop || $test$plusargs("disable_assert_final_checks")) \
      else begin                                                             \
        `ASSERT_ERROR(__name)                                                \
      end                                                                    \
  end                                                                        \
`endif
`define ASSERT_AT_RESET(__name, __prop, __rst = `ASSERT_DEFAULT_RST)          \
  
  
  
  
  
  
  
  
  
  
`ifndef FPV_ON                                                                \
  __name: assert property (@(posedge __rst) $isunknown(__rst) || (__prop))    \
`else                                                                         \
  __name: assert property (@(posedge __rst) (__prop))                         \
`endif                                                                        \
    else begin                                                                \
      `ASSERT_ERROR(__name)                                                   \
    end
`define ASSERT_AT_RESET_AND_FINAL(__name, __prop, __rst = `ASSERT_DEFAULT_RST) \
    `ASSERT_AT_RESET(AtReset_``__name``, __prop, __rst)                        \
    `ASSERT_FINAL(Final_``__name``, __prop)
`define ASSERT(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assert property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop))       \
    else begin                                                                           \
      `ASSERT_ERROR(__name)                                                              \
    end
`define ASSERT_NEVER(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assert property (@(posedge __clk) disable iff ((__rst) !== '0) not (__prop))         \
    else begin                                                                                 \
      `ASSERT_ERROR(__name)                                                                    \
    end
`define ASSERT_KNOWN(__name, __sig, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifndef FPV_ON                                                                                \
  `ASSERT(__name, !$isunknown(__sig), __clk, __rst)                                           \
`endif
`define COVER(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: cover property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop));
`define ASSUME(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  __name: assume property (@(posedge __clk) disable iff ((__rst) !== '0) (__prop))       \
    else begin                                                                           \
      `ASSERT_ERROR(__name)                                                              \
    end
`define ASSUME_I(__name, __prop) \
  __name: assume (__prop)        \
    else begin                   \
      `ASSERT_ERROR(__name)      \
    end
 `define INC_ASSERT
`endif
`define ASSERT_PULSE(__name, __sig, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ASSERT(__name, $rose(__sig) |=> !(__sig), __clk, __rst)
`define ASSERT_IF(__name, __prop, __enable, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ASSERT(__name, (__enable) |-> (__prop), __clk, __rst)
`define ASSERT_KNOWN_IF(__name, __sig, __enable, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifndef FPV_ON                                                                                             \
  `ASSERT_KNOWN(__name``KnownEnable, __enable, __clk, __rst)                                               \
  `ASSERT_IF(__name, !$isunknown(__sig), __enable, __clk, __rst)                                           \
`endif
`define ASSUME_FPV(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifdef FPV_ON                                                                                \
   `ASSUME(__name, __prop, __clk, __rst)                                                     \
`endif
`define ASSUME_I_FPV(__name, __prop) \
`ifdef FPV_ON                        \
   `ASSUME_I(__name, __prop)         \
`endif
`define COVER_FPV(__name, __prop, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
`ifdef FPV_ON                                                                               \
   `COVER(__name, __prop, __clk, __rst)                                                     \
`endif
`define ASSERT_FPV_LINEAR_FSM(__name, __state, __type, __clk = `ASSERT_DEFAULT_CLK, __rst = `ASSERT_DEFAULT_RST) \
  `ifdef INC_ASSERT                                                                                              \
     bit __name``_cond;                                                                                          \
     always_ff @(posedge __clk or posedge __rst) begin                                                           \
       if (__rst) begin                                                                                          \
         __name``_cond <= 0;                                                                                     \
       end else begin                                                                                            \
         __name``_cond <= 1;                                                                                     \
       end                                                                                                       \
     end                                                                                                         \
     property __name``_p;                                                                                        \
       __type initial_state;                                                                                     \
       (!$stable(__state) & __name``_cond, initial_state = $past(__state)) |->                                   \
           (__state != initial_state) until !(__name``_cond);                                                    \
     endproperty                                                                                                 \
   `ASSERT(__name, __name``_p, __clk, 0)                                                                         \
  `endif
