`ifndef PRIM_FLOP_MACROS_SV
`define PRIM_FLOP_MACROS_SV
`define PRIM_FLOP_CLK clk_i
`define PRIM_FLOP_RST rst_ni
`define PRIM_FLOP_RESVAL '0
`define PRIM_FLOP_A(__d, __q, __resval = `PRIM_FLOP_RESVAL, __clk = `PRIM_FLOP_CLK, __rst_n = `PRIM_FLOP_RST) \
  always_ff @(posedge __clk or negedge __rst_n) begin \
    if (!__rst_n) begin                               \
      __q <= __resval;                                \
    end else begin                                    \
      __q <= __d;                                     \
    end                                               \
  end
`define PRIM_FLOP_SPARSE_FSM(__name, __d, __q, __type, __resval = `PRIM_FLOP_RESVAL, __clk = `PRIM_FLOP_CLK, __rst_n = `PRIM_FLOP_RST, __alert_trigger_sva_en = 1) \
  `ifdef SIMULATION                                   \
    prim_sparse_fsm_flop #(                           \
      .StateEnumT(__type),                            \
      .Width($bits(__type)),                          \
      .ResetValue($bits(__type)'(__resval)),          \
      .EnableAlertTriggerSVA(__alert_trigger_sva_en), \
      .CustomForceName(`PRIM_STRINGIFY(__q))          \
    ) __name (                                        \
      .clk_i   ( __clk   ),                           \
      .rst_ni  ( __rst_n ),                           \
      .state_i ( __d     ),                           \
      .state_o (         )                            \
    );                                                \
    `PRIM_FLOP_A(__d, __q, __resval, __clk, __rst_n)  \
    `ASSERT(``__name``_A, __q === ``__name``.state_o) \
  `else                                               \
    prim_sparse_fsm_flop #(                           \
      .StateEnumT(__type),                            \
      .Width($bits(__type)),                          \
      .ResetValue($bits(__type)'(__resval)),          \
      .EnableAlertTriggerSVA(__alert_trigger_sva_en)  \
    ) __name (                                        \
      .clk_i   ( __clk   ),                           \
      .rst_ni  ( __rst_n ),                           \
      .state_i ( __d     ),                           \
      .state_o ( __q     )                            \
    );                                                \
  `endif
`endif 
`endif 
module keymgr_dpe_op_state_ctrl
  import keymgr_dpe_pkg::*;
  import keymgr_dpe_reg_pkg::*;
(
  input clk_i,
  input rst_ni,
  input adv_req_i,
  input gen_req_i,
  input erase_req_i,
  input dis_req_i,
  input load_req_i,
  
  output logic op_ack_o,
  output logic op_busy_o,
  
  output logic op_update_o,
  input kmac_done_i,
  output logic adv_en_o,
  output logic gen_en_o,
  output logic op_fsm_err_o
);
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  localparam int StateWidth = 8;
  typedef enum logic [StateWidth-1:0] {
    StIdle = 8'b11101110,
    StAdv = 8'b00000101,
    StWait = 8'b01110011,
    StSingleCycle = 8'b10011000
  } state_e;
  state_e state_q, state_d;
  `PRIM_FLOP_SPARSE_FSM(u_state_regs, state_d, state_q, state_e, StIdle)
  logic gen_en;
  assign gen_en_o = gen_en & gen_req_i;
  always_comb begin
    state_d = state_q;
    op_update_o = 1'b0;
    op_ack_o = 1'b0;
    op_busy_o = 1'b0;
    
    adv_en_o = 1'b0;
    gen_en = 1'b0;
    op_fsm_err_o = 1'b0;
    unique case (state_q)
      StIdle: begin
        if (dis_req_i) begin
          state_d = StSingleCycle;
        end else if (adv_req_i) begin
          state_d = StAdv;
        end else if (gen_req_i) begin
          state_d = StWait;
        end else if (erase_req_i) begin
          state_d = StSingleCycle;
        end else if (load_req_i) begin
          state_d = StSingleCycle;
        end
      end
      
      
      
      
      StSingleCycle: begin
        op_ack_o = 1'b1;
        op_update_o = 1'b1;
        state_d = StIdle;
      end
      StAdv: begin
        adv_en_o = 1'b1;
        op_busy_o = 1'b1;
        if (kmac_done_i) begin
          op_ack_o = 1'b1;
          op_update_o = 1'b1;
          state_d = StIdle;
        end
      end
      
      StWait: begin
        gen_en = 1'b1;
        op_busy_o = 1'b1;
        if (kmac_done_i) begin
          op_ack_o = 1'b1;
          state_d = StIdle;
        end
      end
      
      default: begin
        
        op_ack_o = 1'b1;
        op_fsm_err_o = 1'b1;
        op_busy_o = 1'b1;
      end
    endcase 
  end
endmodule 

package keymgr_dpe_pkg;
  
  import keymgr_pkg::*;
  parameter int DpeNumSlots = 8;
  parameter int DpeNumSlotsWidth = prim_util_pkg::vbits(DpeNumSlots);
  
  
  
  
  
  
  
  
  parameter int DpeAdvDataWidth = SwBindingWidth + KeyWidth + otp_ctrl_pkg::DeviceIdWidth +
      lc_ctrl_pkg::LcKeymgrDivWidth + KeyWidth*keymgr_dpe_reg_pkg::NumRomDigestInputs + KeyWidth;
  typedef logic [DpeNumSlotsWidth-1:0] keymgr_dpe_slot_idx_e;
  
  typedef enum logic [2:0] {
    OpDpeAdvance = 0,
    OpDpeErase = 1,
    OpDpeGenSwOut = 2,
    OpDpeGenHwOut = 3,
    OpDpeDisable = 4,
    OpDpeLoadRootKey = 5
  } keymgr_dpe_ops_e;
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  
  localparam int StateWidth = 10;
  typedef enum logic [StateWidth-1:0] {
    StCtrlDpeReset         = 10'b1000011111,
    StCtrlDpeEntropyReseed = 10'b1111000011,
    StCtrlDpeRandom        = 10'b0001110010,
    StCtrlDpeRootKey       = 10'b0110101010,
    StCtrlDpeAvailable     = 10'b0111111101,
    StCtrlDpeWipe          = 10'b0001000101,
    StCtrlDpeDisabling     = 10'b1010110001,
    StCtrlDpeDisabled      = 10'b1100100100,
    StCtrlDpeInvalid       = 10'b1101011000
  } keymgr_dpe_working_state_e;
  
  typedef enum logic [1:0] {
    StWorkDpeReset = 0,
    StWorkDpeAvailable,
    StWorkDpeDisabled,
    StWorkDpeInvalid
  } keymgr_dpe_exposed_working_state_e;
  
  typedef struct packed {
    logic retain_parent;
    logic exportable;
    logic allow_child;
  } keymgr_dpe_policy_t;
  
  
  parameter int DpeBootStagesWidth = 2;
  typedef enum logic [DpeBootStagesWidth-1:0] {
    BootStageCreator = 0,
    BootStageOwner   = 1,
    BootStageRuntime = 2
  } keymgr_dpe_boot_stage_e;
  
  typedef struct packed {
    logic valid;
    keymgr_dpe_boot_stage_e boot_stage;
    logic [Shares-1:0][KeyWidth-1:0] key;
    logic [KeyVersionWidth-1:0] max_key_version;
    keymgr_dpe_policy_t key_policy;
  } keymgr_dpe_slot_t;
  typedef enum logic [2:0] {
    SlotUpdateIdle,
    SlotDestRandomize,
    SlotLoadRoot,
    SlotLoadFromKmac,
    SlotErase,
    SlotWipeInternalOnly,
    SlotWipeAll
  } keymgr_dpe_key_update_e;
  localparam keymgr_dpe_policy_t DEFAULT_UDS_POLICY = '{
    retain_parent : 1'b0,
    exportable    : 1'b0,
    allow_child   : 1'b1
  };
  
  typedef enum logic [2:0] {
    KeymgrDpeEnCtrl,
    KeymgrDpeEnCfg,
    KeymgrDpeEnBinding,
    KeymgrDpeEnDebug,
    KeymgrDpeEnLast
  } keymgr_lc_en_usage_e;
endpackage : keymgr_dpe_pkg

