    160'h62089181d2a6be2ce145e2e27099ededbd7dceb0
  };
  
  
  parameter int AdvDataWidth = SwBindingWidth + 2*KeyWidth + DevIdWidth + HealthStateWidth;
  parameter int IdDataWidth = KeyWidth;
  
